# if/elif/else example
x = 10
if x > 10:
    print('x is greater than 10')
elif x == 10:
    print('x is equal to 10')
else:
    print('x is less than 10')

# for loop using range
for i in range(3):
    print(f'Loop index: {i}')

# while loop example
count = 0
while count < 3:
    print(f'Count: {count}')
    count += 1

# Using break and continue
for i in range(5):
    if i == 2:
        continue  # Skip when i is 2
    if i == 4:
        break    # Exit loop when i is 4
    print(f'i: {i}')

# try/except/finally block
try:
    result = 10 / 0
except ZeroDivisionError as e:
    print('Caught an exception:', e)
finally:
    print('Finally block executed')

def my_function(param1, param2='default'):
    print(f'param1: {param1}, param2: {param2}')
    return param1

result = my_function('value1')
print('Function returned:', result)

def recursive_factorial(n):
    if n <= 1:
        return 1
    else:
        return n * recursive_factorial(n-1)

print('Factorial of 5:', recursive_factorial(5))

try:
    int('abc')  # This will raise a ValueError
except ValueError as e:
    print('Caught ValueError:', e)
finally:
    print('Execution of try/except/finally complete')

# Raising an exception explicitly
def check_positive(n):
    if n < 0:
        raise ValueError('Number must be positive')
    return n

try:
    print(check_positive(-5))
except ValueError as e:
    print('Error:', e)
